"use client";

import * as React from "react";
import {
  IconBell,
  IconBox,
  IconBuildingStore,
  IconCamera,
  IconClock,
  IconHome,
  IconMapPin,
  IconPackage,
  IconPlus,
  IconQrcode,
  IconShieldCheck,
  IconTrash,
} from "@tabler/icons-react";
import {
  Badge,
  BottomActionBar,
  Button,
  Card,
  CardContent,
  Checkbox,
  FileUploader,
  ListCard,
  PageHeader,
  RadioCard,
  RadioCardGroup,
  SegmentedControl,
  Select,
  Separator,
  Sheet,
  SheetClose,
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetTitle,
  Switch,
  TicketStub,
  Input,
} from "@gunjo/ui";

import { SettingGroup, SettingRow } from "./SettingRow";

// ---------------------------------------------------------------------------
// ドメインデータ（ツバメ宅急便 会員サービス — 受取・配達設定）
// ---------------------------------------------------------------------------

const OKIHAI_PLACES = [
  {
    value: "genkan",
    title: "玄関ドア前",
    description: "建物の共用部ではなく、ご自宅の玄関前に置きます",
    icon: <IconHome className="size-5" aria-hidden="true" />,
  },
  {
    value: "takuhai-box",
    title: "宅配ボックス",
    description: "空きがない場合は次の指定場所へ",
    icon: <IconBox className="size-5" aria-hidden="true" />,
  },
  {
    value: "monooki",
    title: "物置・倉庫",
    description: "施錠していない物置に置きます",
    icon: <IconPackage className="size-5" aria-hidden="true" />,
  },
  {
    value: "gas-meter",
    title: "ガスメーターボックス",
    description: "雨に濡れにくい場所として",
    icon: <IconBox className="size-5" aria-hidden="true" />,
  },
  {
    value: "shitei",
    title: "指定場所（自由入力）",
    description: "写真とメモでドライバーに伝えます",
    icon: <IconMapPin className="size-5" aria-hidden="true" />,
  },
] as const;

const ABSENT_DEFAULTS = [
  {
    value: "okihai",
    title: "置き配する",
    description: "ご指定の置き配場所へお届け（推奨）",
    highlight: "再配達なしで受け取れます",
  },
  {
    value: "eigyosho",
    title: "営業所止め",
    description: "最寄りの営業所でお預かり",
  },
  {
    value: "conveni",
    title: "コンビニ受取",
    description: "登録したコンビニでお受け取り",
  },
  {
    value: "mochimodori",
    title: "持ち戻り（再配達）",
    description: "一旦持ち帰り、再配達のご連絡をします",
  },
] as const;

const WEEKDAYS = [
  { value: "mon", label: "月" },
  { value: "tue", label: "火" },
  { value: "wed", label: "水" },
  { value: "thu", label: "木" },
  { value: "fri", label: "金" },
  { value: "sat", label: "土" },
  { value: "sun", label: "日" },
];

const TIME_BANDS = [
  { value: "am", label: "午前中（〜12時）" },
  { value: "14-16", label: "14〜16時" },
  { value: "16-18", label: "16〜18時" },
  { value: "18-20", label: "18〜20時" },
  { value: "19-21", label: "19〜21時" },
];

type ReceiveLocation = {
  id: string;
  kind: "自宅" | "コンビニ" | "PUDO" | "駅" | "営業所";
  name: string;
  address: string;
  primary?: boolean;
};

const INITIAL_LOCATIONS: ReceiveLocation[] = [
  {
    id: "home",
    kind: "自宅",
    name: "ご自宅",
    address: "東京都墨田区押上1-1-2 つばめハイツ305",
    primary: true,
  },
  {
    id: "conveni-1",
    kind: "コンビニ",
    name: "ローソン 押上駅前店",
    address: "東京都墨田区押上1-10-3",
  },
  {
    id: "pudo-1",
    kind: "PUDO",
    name: "PUDO 押上スカイツリー前",
    address: "東京都墨田区業平1-1-1 駅構内",
  },
];

const LOCATION_TONE: Record<
  ReceiveLocation["kind"],
  React.ComponentProps<typeof Badge>["variant"]
> = {
  自宅: "default",
  コンビニ: "info",
  PUDO: "secondary",
  駅: "secondary",
  営業所: "warning",
};

// 通知設定（イベント × チャネル）
type Channel = "line" | "mail" | "push" | "sms";
type NotifyEvent = "yotei" | "fuzai" | "tokan";

const NOTIFY_EVENTS: { key: NotifyEvent; label: string; description: string }[] = [
  { key: "yotei", label: "配達予定の通知", description: "お届け前日・当日にお知らせ" },
  { key: "fuzai", label: "不在通知", description: "お届けできなかったときに" },
  { key: "tokan", label: "投函完了の通知", description: "ポスト投函・置き配完了時に" },
];

const CHANNELS: { key: Channel; label: string }[] = [
  { key: "line", label: "LINE" },
  { key: "mail", label: "メール" },
  { key: "push", label: "アプリのプッシュ" },
  { key: "sms", label: "SMS" },
];

// ---------------------------------------------------------------------------

export default function DeliverySettingsPage() {
  // 置き配
  const [okihaiOn, setOkihaiOn] = React.useState(true);
  const [okihaiPlace, setOkihaiPlace] = React.useState<string>("genkan");
  const [okihaiPhotos, setOkihaiPhotos] = React.useState<File[]>([]);
  const [okihaiConsent, setOkihaiConsent] = React.useState(true);
  const [inkanLess, setInkanLess] = React.useState(true);

  // 不在時の対応
  const [absentDefault, setAbsentDefault] = React.useState<string>("okihai");

  // 受取日時
  const [weekday, setWeekday] = React.useState<string>("sat");
  const [timeBand, setTimeBand] = React.useState<string>("18-20");

  // 受取場所
  const [locations, setLocations] =
    React.useState<ReceiveLocation[]>(INITIAL_LOCATIONS);
  const [editing, setEditing] = React.useState<ReceiveLocation | null>(null);
  const [sheetOpen, setSheetOpen] = React.useState(false);

  // 通知設定（既定値）
  const [notify, setNotify] = React.useState<
    Record<NotifyEvent, Record<Channel, boolean>>
  >({
    yotei: { line: true, mail: false, push: true, sms: false },
    fuzai: { line: true, mail: true, push: true, sms: true },
    tokan: { line: true, mail: false, push: true, sms: false },
  });

  const [saved, setSaved] = React.useState(false);

  const toggleNotify = (event: NotifyEvent, channel: Channel) =>
    setNotify((prev) => ({
      ...prev,
      [event]: { ...prev[event], [channel]: !prev[event][channel] },
    }));

  const openEdit = (loc: ReceiveLocation | null) => {
    setEditing(
      loc ?? {
        id: `loc-${Date.now()}`,
        kind: "コンビニ",
        name: "",
        address: "",
      },
    );
    setSheetOpen(true);
  };

  const saveLocation = () => {
    if (!editing) return;
    setLocations((prev) => {
      const exists = prev.some((l) => l.id === editing.id);
      return exists
        ? prev.map((l) => (l.id === editing.id ? editing : l))
        : [...prev, editing];
    });
    setSheetOpen(false);
    setEditing(null);
  };

  const removeLocation = (id: string) =>
    setLocations((prev) => prev.filter((l) => l.id !== id));

  const placeLabel =
    OKIHAI_PLACES.find((p) => p.value === okihaiPlace)?.title ?? "未設定";
  const absentLabel =
    ABSENT_DEFAULTS.find((a) => a.value === absentDefault)?.title ?? "未設定";
  const weekdayLabel = WEEKDAYS.find((w) => w.value === weekday)?.label ?? "";
  const timeBandLabel = TIME_BANDS.find((t) => t.value === timeBand)?.label ?? "";
  const activeNotifyCount = Object.values(notify)
    .flatMap((c) => Object.values(c))
    .filter(Boolean).length;

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-muted/30">
      <PageHeader
        title="受取・配達設定"
        subtitle="ツバメ宅急便 会員サービス"
        onBack={() => {}}
        actions={
          <Button variant="ghost" size="sm" type="button">
            マイページ
          </Button>
        }
      />

      <main className="flex flex-1 flex-col gap-6 px-4 py-5 pb-8">
        {/* ---------------- デジタル会員証 ---------------- */}
        <section aria-labelledby="member-heading">
          <h2 id="member-heading" className="sr-only">
            デジタル会員証
          </h2>
          <TicketStub
            value="9821-4470-1183"
            format="qr"
            codeLabel="会員番号 9821-4470-1183"
            codeAlt="会員番号 9821-4470-1183 のQRコード。営業所・PUDO・コンビニのスキャナーにかざしてください"
          >
            <div className="flex items-start justify-between gap-3">
              <div className="min-w-0">
                <p className="text-xs text-muted-foreground">ツバメ宅急便メンバー</p>
                <p className="truncate text-lg font-bold text-foreground">
                  押上 つばさ 様
                </p>
                <p className="mt-0.5 text-xs text-muted-foreground">
                  会員番号 9821-4470-1183
                </p>
              </div>
              <Badge variant="warning" className="shrink-0">
                ゴールド
              </Badge>
            </div>
            <div className="mt-3 flex items-center gap-1.5 text-xs text-muted-foreground">
              <IconQrcode className="size-4" aria-hidden="true" />
              受け取り時にこのコードを提示
            </div>
          </TicketStub>
        </section>

        {/* ---------------- 置き配の設定 ---------------- */}
        <section aria-labelledby="okihai-heading" className="space-y-3">
          <h2
            id="okihai-heading"
            className="px-1 text-base font-semibold text-foreground"
          >
            置き配（おき配）の設定
          </h2>

          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between gap-3">
                <div className="min-w-0">
                  <p className="font-medium text-foreground">置き配を利用する</p>
                  <p className="mt-0.5 text-sm text-muted-foreground">
                    不在でもご指定の場所へお届けします
                  </p>
                </div>
                <Switch
                  checked={okihaiOn}
                  onCheckedChange={setOkihaiOn}
                  aria-label="置き配を利用する"
                />
              </div>
            </CardContent>
          </Card>

          {okihaiOn && (
            <>
              <fieldset className="space-y-2">
                <legend className="mb-1 px-1 text-sm font-medium text-foreground">
                  置き配場所を選ぶ
                </legend>
                <RadioCardGroup
                  value={okihaiPlace}
                  onValueChange={setOkihaiPlace}
                  aria-label="置き配場所"
                >
                  {OKIHAI_PLACES.map((p) => (
                    <RadioCard
                      key={p.value}
                      value={p.value}
                      title={p.title}
                      description={p.description}
                      leading={p.icon}
                    />
                  ))}
                </RadioCardGroup>
              </fieldset>

              <Card>
                <CardContent className="space-y-3 p-4">
                  <div className="flex items-center gap-2">
                    <IconCamera
                      className="size-5 text-muted-foreground"
                      aria-hidden="true"
                    />
                    <p className="font-medium text-foreground">
                      置き配場所の写真
                    </p>
                  </div>
                  <p className="text-sm text-muted-foreground">
                    ドライバーが置き場所を間違えないよう、目印になる写真を登録できます（最大2枚）。
                  </p>
                  <FileUploader
                    value={okihaiPhotos}
                    onValueChange={setOkihaiPhotos}
                    maxFiles={2}
                    maxSize={5 * 1024 * 1024}
                    accept={{ "image/*": [".jpg", ".jpeg", ".png", ".heic"] }}
                    labels={{
                      browse: "写真を選ぶ",
                      drop: "写真をここにドラッグ、またはタップして選択",
                      maxSize: (mb) => `1枚あたり最大 ${mb}MB`,
                      removeFile: "写真を削除",
                    }}
                  />
                </CardContent>
              </Card>

              <Card>
                <CardContent className="space-y-3 p-4">
                  <Checkbox
                    checked={okihaiConsent}
                    onCheckedChange={setOkihaiConsent}
                    label="置き配の利用に同意します"
                    description="盗難・破損等のリスクをご理解のうえご利用ください。同意がない場合、置き配は行いません。"
                  />
                  <Separator />
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0">
                      <p className="font-medium text-foreground">
                        印鑑レス・受領印不要
                      </p>
                      <p className="mt-0.5 text-sm text-muted-foreground">
                        対面時もサイン・印鑑なしで受け取ります
                      </p>
                    </div>
                    <Switch
                      checked={inkanLess}
                      onCheckedChange={setInkanLess}
                      aria-label="印鑑レス・受領印不要"
                    />
                  </div>
                </CardContent>
              </Card>
            </>
          )}
        </section>

        {/* ---------------- 不在時の対応（既定） ---------------- */}
        <fieldset aria-labelledby="absent-heading" className="space-y-2">
          <legend
            id="absent-heading"
            className="px-1 text-base font-semibold text-foreground"
          >
            不在時の対応（既定）
          </legend>
          <p className="px-1 text-sm text-muted-foreground">
            指定がない荷物に、初期設定として適用されます。
          </p>
          <RadioCardGroup
            value={absentDefault}
            onValueChange={setAbsentDefault}
            aria-label="不在時の対応"
            className="mt-1"
          >
            {ABSENT_DEFAULTS.map((a) => (
              <RadioCard
                key={a.value}
                value={a.value}
                title={a.title}
                description={a.description}
                highlight={"highlight" in a ? a.highlight : undefined}
              />
            ))}
          </RadioCardGroup>
        </fieldset>

        {/* ---------------- 受取場所の登録 ---------------- */}
        <section aria-labelledby="locations-heading" className="space-y-3">
          <div className="flex items-center justify-between gap-2 px-1">
            <h2
              id="locations-heading"
              className="text-base font-semibold text-foreground"
            >
              受取場所の登録
            </h2>
            <Button
              variant="outline"
              size="sm"
              type="button"
              onClick={() => openEdit(null)}
            >
              <IconPlus className="size-4" aria-hidden="true" />
              追加
            </Button>
          </div>

          <div className="space-y-2">
            {locations.map((loc) => (
              <ListCard
                key={loc.id}
                leading={<LocationIcon kind={loc.kind} />}
                title={loc.name}
                description={loc.address}
                status={
                  <Badge variant={LOCATION_TONE[loc.kind]}>{loc.kind}</Badge>
                }
                tags={
                  loc.primary ? (
                    <Badge variant="success">よく使う</Badge>
                  ) : undefined
                }
                trailing={
                  <div className="flex items-center gap-1">
                    <Button
                      variant="ghost"
                      size="sm"
                      type="button"
                      onClick={() => openEdit(loc)}
                    >
                      編集
                    </Button>
                    {!loc.primary && (
                      <Button
                        variant="ghost"
                        size="icon"
                        type="button"
                        aria-label={`${loc.name} を削除`}
                        onClick={() => removeLocation(loc.id)}
                      >
                        <IconTrash className="size-4" aria-hidden="true" />
                      </Button>
                    )}
                  </div>
                }
              />
            ))}
          </div>
        </section>

        {/* ---------------- 受取日時の希望（既定） ---------------- */}
        <section aria-labelledby="datetime-heading" className="space-y-3">
          <h2
            id="datetime-heading"
            className="px-1 text-base font-semibold text-foreground"
          >
            受取日時の希望（既定）
          </h2>

          <Card>
            <CardContent className="space-y-4 p-4">
              <div>
                <p className="mb-2 text-sm font-medium text-foreground">曜日</p>
                <SegmentedControl
                  options={WEEKDAYS}
                  value={weekday}
                  onValueChange={setWeekday}
                  size="lg"
                  aria-label="希望曜日"
                />
              </div>
              <Select
                label="時間帯"
                value={timeBand}
                onChange={(e) => setTimeBand(e.target.value)}
              >
                {TIME_BANDS.map((t) => (
                  <option key={t.value} value={t.value}>
                    {t.label}
                  </option>
                ))}
              </Select>
            </CardContent>
          </Card>
        </section>

        {/* ---------------- 通知設定 ---------------- */}
        <section aria-labelledby="notify-heading" className="space-y-3">
          <h2
            id="notify-heading"
            className="px-1 text-base font-semibold text-foreground"
          >
            通知設定
          </h2>

          {NOTIFY_EVENTS.map((event) => (
            <SettingGroup
              key={event.key}
              title={
                <span className="flex items-center gap-2">
                  <IconBell
                    className="size-4 text-muted-foreground"
                    aria-hidden="true"
                  />
                  {event.label}
                </span>
              }
            >
              <div className="px-4 pt-3 text-xs text-muted-foreground">
                {event.description}
              </div>
              <fieldset>
                <legend className="sr-only">
                  {event.label}の通知チャネル
                </legend>
                {CHANNELS.map((ch, i) => (
                  <div
                    key={ch.key}
                    className={
                      "flex items-center justify-between gap-3 px-4 py-3" +
                      (i < CHANNELS.length - 1 ? " border-b border-border" : "")
                    }
                  >
                    <span className="text-sm text-foreground">{ch.label}</span>
                    <Switch
                      checked={notify[event.key][ch.key]}
                      onCheckedChange={() => toggleNotify(event.key, ch.key)}
                      aria-label={`${event.label}を${ch.label}で受け取る`}
                    />
                  </div>
                ))}
              </fieldset>
            </SettingGroup>
          ))}
        </section>

        {/* ---------------- まとめ（現在の設定） — settings/nav rows ---------------- */}
        <SettingGroup title="現在の設定">
          <SettingRow
            leading={<IconPackage className="size-5" aria-hidden="true" />}
            label="置き配"
            value={okihaiOn ? placeLabel : "利用しない"}
          />
          <SettingRow
            leading={<IconShieldCheck className="size-5" aria-hidden="true" />}
            label="不在時の対応"
            value={absentLabel}
          />
          <SettingRow
            leading={<IconClock className="size-5" aria-hidden="true" />}
            label="受取日時"
            value={`${weekdayLabel}・${timeBandLabel}`}
          />
          <SettingRow
            leading={<IconBell className="size-5" aria-hidden="true" />}
            label="通知"
            value={`${activeNotifyCount} 件オン`}
            last
          />
        </SettingGroup>
      </main>

      <BottomActionBar
        actions={
          <Button
            type="button"
            size="xl"
            onClick={() => {
              setSaved(true);
              window.setTimeout(() => setSaved(false), 2000);
            }}
          >
            設定を保存
          </Button>
        }
      >
        <p className="text-sm font-medium text-foreground">
          {saved ? "保存しました" : "未保存の変更があります"}
        </p>
        <p className="text-xs text-muted-foreground">
          置き配: {okihaiOn ? placeLabel : "オフ"} ／ 不在時: {absentLabel}
        </p>
      </BottomActionBar>

      {/* ---------------- 受取場所の編集シート ---------------- */}
      <Sheet open={sheetOpen} onOpenChange={setSheetOpen}>
        <SheetContent side="bottom" className="rounded-t-2xl">
          <SheetHeader>
            <SheetTitle>受取場所の編集</SheetTitle>
            <SheetDescription>
              ご自宅・コンビニ・PUDO・駅・営業所を登録できます。
            </SheetDescription>
          </SheetHeader>

          {editing && (
            <div className="mt-4 space-y-4">
              <Select
                label="種別"
                value={editing.kind}
                onChange={(e) =>
                  setEditing({
                    ...editing,
                    kind: e.target.value as ReceiveLocation["kind"],
                  })
                }
              >
                {(["自宅", "コンビニ", "PUDO", "駅", "営業所"] as const).map(
                  (k) => (
                    <option key={k} value={k}>
                      {k}
                    </option>
                  ),
                )}
              </Select>
              <div className="space-y-1.5">
                <label
                  htmlFor="loc-name"
                  className="text-sm font-medium text-foreground"
                >
                  名称
                </label>
                <Input
                  id="loc-name"
                  value={editing.name}
                  placeholder="例：ローソン 押上駅前店"
                  onChange={(e) =>
                    setEditing({ ...editing, name: e.target.value })
                  }
                />
              </div>
              <div className="space-y-1.5">
                <label
                  htmlFor="loc-address"
                  className="text-sm font-medium text-foreground"
                >
                  住所
                </label>
                <Input
                  id="loc-address"
                  value={editing.address}
                  placeholder="例：東京都墨田区押上1-10-3"
                  onChange={(e) =>
                    setEditing({ ...editing, address: e.target.value })
                  }
                />
              </div>
            </div>
          )}

          <SheetFooter className="mt-6 flex-row gap-3">
            <SheetClose asChild>
              <Button variant="outline" type="button" className="flex-1">
                キャンセル
              </Button>
            </SheetClose>
            <Button
              type="button"
              className="flex-1"
              disabled={!editing?.name || !editing?.address}
              onClick={saveLocation}
            >
              保存
            </Button>
          </SheetFooter>
        </SheetContent>
      </Sheet>
    </div>
  );
}

function LocationIcon({ kind }: { kind: ReceiveLocation["kind"] }) {
  const cls = "size-5 text-muted-foreground";
  if (kind === "自宅") return <IconHome className={cls} aria-hidden="true" />;
  if (kind === "コンビニ")
    return <IconBuildingStore className={cls} aria-hidden="true" />;
  if (kind === "営業所")
    return <IconBuildingStore className={cls} aria-hidden="true" />;
  return <IconMapPin className={cls} aria-hidden="true" />;
}

"use client";

import * as React from "react";
import { IconChevronRight } from "@tabler/icons-react";
import { cn } from "@gunjo/ui";

/**
 * HAND-ROLLED — see the report. @gunjo/ui has no "settings / nav row": a flush,
 * full-bleed tappable row with `label + current value + chevron` that *navigates
 * into a detail* (opens a Sheet here). The kit's by-use-case index routes this to
 * `ListCard`, but `ListCard.onSelect` renders `aria-pressed` toggle semantics
 * (a button that reports an on/off state), which is wrong for "tap to open the
 * next screen" — a screen reader would announce it as a toggle. `ListCard` is also
 * a bordered card, not the flush iOS/Android grouped-settings row. So this is the
 * gap: a `NavRow`/`SettingsRow` primitive. Kept minimal + accessible.
 */
export interface SettingRowProps {
  /** Leading icon / accessory. */
  leading?: React.ReactNode;
  /** Primary label. */
  label: React.ReactNode;
  /** Secondary line under the label. */
  description?: React.ReactNode;
  /** Right-aligned current value (truncates). */
  value?: React.ReactNode;
  /** Opens the detail. When set, the whole row is a ≥44px button + chevron. */
  onClick?: () => void;
  /** Suppress the divider under the row (last row in a group). */
  last?: boolean;
}

export function SettingRow({
  leading,
  label,
  description,
  value,
  onClick,
  last,
}: SettingRowProps) {
  const inner = (
    <>
      {leading != null && (
        <span className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-muted text-foreground">
          {leading}
        </span>
      )}
      <span className="min-w-0 flex-1 text-left">
        <span className="block truncate font-medium text-foreground">{label}</span>
        {description != null && (
          <span className="mt-0.5 block truncate text-xs text-muted-foreground">
            {description}
          </span>
        )}
      </span>
      {value != null && (
        <span className="ml-auto max-w-[45%] shrink-0 truncate text-right text-sm text-muted-foreground">
          {value}
        </span>
      )}
      {onClick != null && (
        <IconChevronRight
          className="size-5 shrink-0 text-muted-foreground"
          aria-hidden="true"
        />
      )}
    </>
  );

  const rowClass = cn(
    "flex w-full min-h-[52px] items-center gap-3 px-4 py-3",
    !last && "border-b border-border",
  );

  if (onClick == null) {
    return <div className={rowClass}>{inner}</div>;
  }

  return (
    <button
      type="button"
      onClick={onClick}
      className={cn(
        rowClass,
        "text-left transition-colors hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-ring",
      )}
    >
      {inner}
    </button>
  );
}

/** A grouped-settings container: a single rounded card the rows sit flush inside. */
export function SettingGroup({
  title,
  children,
  className,
}: {
  title?: React.ReactNode;
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <section className={cn("w-full", className)}>
      {title != null && (
        <h2 className="mb-2 px-1 text-sm font-semibold text-foreground">{title}</h2>
      )}
      <div className="overflow-hidden rounded-xl border border-border bg-card">
        {children}
      </div>
    </section>
  );
}
